SELECT galaxy_id
FROM galaxies
WHERE class = 'elliptical' AND fSize > 10;

SELECT galaxy_id, fSize, fConc, fAsym
FROM galaxies
ORDER BY fSize DESC;

SELECT AVG(redshift) AS average_redshift
FROM galaxies
WHERE class = 'Spiral';

SELECT "fLength", "class"
FROM "galaxies"
WHERE "redshift" > 1;

SELECT * 
FROM galaxies
WHERE fLength = (SELECT MAX(fLength) FROM galaxies);

SELECT name, last_active
FROM researchers
ORDER BY last_active DESC;

SELECT DISTINCT researchers.name
FROM researchers
INNER JOIN galaxy_classifications ON researchers.researcher_id = galaxy_classifications.researcher_id;

SELECT galaxies.galaxy_id, galaxy_types.type_name
FROM galaxies
JOIN galaxy_types ON galaxies.class = galaxy_types.type_id;

SELECT galaxy_id, fSize
FROM galaxies
ORDER BY fSize ASC;
